// mm/src/pages/login.js
import React, { useMemo, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';

function isValidEmail(email) {
  const v = String(email || '').trim().toLowerCase();
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(v);
}

export default function LoginPage() {
  const nav = useNavigate();

  const [form, setForm] = useState({
    email: '',
    password: '',
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  const canSubmit = useMemo(() => {
    return isValidEmail(form.email) && String(form.password || '').length > 0 && !loading;
  }, [form.email, form.password, loading]);

  const handleChange = (e) => {
    setError('');
    setSuccessMsg('');
    const { name, value } = e.target;
    setForm((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');

    const email = String(form.email || '').trim().toLowerCase();
    const password = String(form.password || '');

    if (!isValidEmail(email)) {
      setError('Please enter a valid email address.');
      return;
    }
    if (!password) {
      setError('Please enter your password.');
      return;
    }

    setLoading(true);
    try {
      const resp = await fetch(
        'https://manuscriptmagic.fowkes.xyz/services/login.php',
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ email, password }),
        }
      );

      const data = await resp.json().catch(() => null);

      // Support a few common response shapes.
      // You said:
      // success => UserId, AccessToken, RenewalToken, message
      // failed  => error message
      const ok =
        data?.success === true ||
        data?.Success === true ||
        data?.status === 'success';

      if (!ok) {
        const msg =
          data?.message ||
          data?.error ||
          data?.Message ||
          'Login failed. Please check your credentials.';
        setError(msg);
        return;
      }

      const userId = data?.UserId ?? data?.userId ?? data?.user?.id ?? '';
      const accessToken = data?.AccessToken ?? data?.accessToken ?? '';
      const renewalToken = data?.RenewalToken ?? data?.renewalToken ?? '';
      const message = data?.message || data?.Message || 'Login successful.';

      // Persist auth
      if (userId) localStorage.setItem('userId', String(userId));
      if (accessToken) localStorage.setItem('accessToken', String(accessToken));
      if (renewalToken) localStorage.setItem('renewalToken', String(renewalToken));

      setSuccessMsg(message);

      // Redirect after login
      nav('/workflow/start');
    } catch (err) {
      console.error(err);
      setError('An error occurred while logging in. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-slate-50 to-slate-100 flex items-center justify-center px-4 py-12">
      <div className="w-full max-w-xl bg-white border border-slate-200 rounded-2xl shadow-sm p-8">
        <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">
          Sign in
        </h1>
        <p className="mt-2 text-slate-500">
          Log in with your email and password.
        </p>

        <form onSubmit={handleSubmit} className="mt-8 space-y-5">
          <div>
            <label className="block text-sm font-medium text-slate-700">
              Email <span className="text-red-500">*</span>
            </label>
            <input
              name="email"
              type="email"
              value={form.email}
              onChange={handleChange}
              placeholder="you@email.com"
              className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
              autoComplete="email"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700">
              Password <span className="text-red-500">*</span>
            </label>
            <input
              name="password"
              type="password"
              value={form.password}
              onChange={handleChange}
              placeholder="Your password"
              className="mt-2 w-full border border-slate-200 rounded-md px-3 py-2 outline-none focus:ring-2 focus:ring-blue-200"
              autoComplete="current-password"
            />
          </div>

          {error ? <div className="text-sm text-red-600">{error}</div> : null}
          {successMsg ? (
            <div className="text-sm text-green-700">{successMsg}</div>
          ) : null}

          <button
            type="submit"
            disabled={!canSubmit}
            className={[
              'w-full py-3 rounded-md text-white font-semibold',
              canSubmit ? 'bg-blue-600 hover:bg-blue-700' : 'bg-slate-300 cursor-not-allowed',
            ].join(' ')}
          >
            {loading ? 'Signing in…' : 'Sign in'}
          </button>

          <div className="text-sm text-slate-600 text-center">
            Don’t have an account?{' '}
            <Link to="/register" className="text-blue-700 hover:underline">
              Create one
            </Link>
          </div>
        </form>
      </div>
    </div>
  );
}
